var kSum = function(nums, k) {
    let maxsum = 0;
    for (const v of nums) if (v > 0) maxsum += v;
    const mags = nums.map(v => Math.abs(v)).sort((a, b) => a - b);
    const n = mags.length;
    // min-heap of [reduction, index]
    const heap = [];
    const push = (item) => {
        heap.push(item);
        let c = heap.length - 1;
        while (c > 0) {
            const p = (c - 1) >> 1;
            if (heap[p][0] <= heap[c][0]) break;
            [heap[p], heap[c]] = [heap[c], heap[p]];
            c = p;
        }
    };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length) {
            heap[0] = last;
            let c = 0;
            const m = heap.length;
            while (true) {
                let l = 2 * c + 1, r = 2 * c + 2, s = c;
                if (l < m && heap[l][0] < heap[s][0]) s = l;
                if (r < m && heap[r][0] < heap[s][0]) s = r;
                if (s === c) break;
                [heap[s], heap[c]] = [heap[c], heap[s]];
                c = s;
            }
        }
        return top;
    };
    if (n) push([mags[0], 0]);
    let result = maxsum;
    for (let step = 0; step < k - 1; step++) {
        if (!heap.length) break;
        const [red, i] = pop();
        result = maxsum - red;
        if (i + 1 < n) {
            push([red + mags[i + 1], i + 1]);
            push([red - mags[i] + mags[i + 1], i + 1]);
        }
    }
    return result;
};
